from django.db import models
from pydantic import BaseModel, Field

class DjangoUser(models.Model):
    name = models.CharField(max_length=64)
    email = models.EmailField()
    class Meta:
        app_label = 'users'

# BUG: Django's ModelBase metaclass and Pydantic's ModelMetaclass are unrelated.
# Python refuses to synthesize a common metaclass for subclasses that inherit both.

class HybridUser(DjangoUser, BaseModel):
    full_name: str = Field(default="")

    def display(self) -> str:
        return f"{self.full_name} <{self.email}>"

if __name__ == '__main__':
    u = HybridUser(name="Ada", email="ada@example.com", full_name="Ada Lovelace")
    print(u.display())
